  @IsString()
  name: string;

  @Column({ type: 'enum', enum: MealPlan })
  @IsEnum(MealPlan)
  mealPlan: MealPlan;

  @ManyToMany(() => GeoCountry)
  @JoinTable({ name: 'price_setting_countries' })
  @ValidateNested({ each: true })
  @Type(() => GeoCountry)
  @IsOptional()
  countries?: GeoCountry[];

  @Column()
  @IsNumber()
  price: number;

  @Column({ enum: PriceType, type: 'enum', nullable: true, default: PriceType.TA })
  @IsEnum(PriceType)
  priceType: PriceType;

  @Column({ nullable: true, default: 'BGT' })
  @IsString()
  source: string;

  @Column({ type: 'jsonb' })
  periods: RangeDate[];

  @ManyToOne(() => Season, season => season.id, { nullable: true })
  @Type(() => Season)
  @ValidateNested()
  season: Season;

  @Column({ type: 'enum', enum: CancellationType })
  @IsEnum(CancellationType)
  condition: CancellationType;

  @Column({ nullable: true })
  @IsNumber()
  cancellationPeriod: number;

  @Column({ type: 'enum', enum: UnitTime, nullable: true })
  @IsEnum(UnitTime)
  cancellationPeriodUnitTime: UnitTime;

  @Column({ type: 'enum', enum: UnitType, nullable: true })
  @IsEnum(UnitType)
  unitType: UnitType;

  @Column({ type: 'decimal', precision: 10, scale: 2, default: 0 })
  @IsNumber()
  amount: number;

  @ManyToOne(() => Room, room => room.id, { onDelete: 'CASCADE' })
  @Type(() => Room)
  @ValidateNested()
  room: Room;

  @ManyToOne(() => Hotel, h => h.id, { onDelete: 'CASCADE' })
  @JoinColumn({ name: 'hotelId' })
  @ValidateNested()
  @Type(() => Hotel)
  hotel: Hotel;

  @Column({ default: true })
  @IsBoolean()
  isActive: boolean;

  /** Áp dụng cho ngày nào trong tuần, lấy từ config mùa type = DAY */
  @Column({ type: 'enum', enum: DayType, nullable: true })
  @IsEnum(DayType)
  @IsOptional()
  dayType?: DayType;

  @AfterLoad()
  sortPeriods() {
    if (this.periods && Array.isArray(this.periods)) {
      this.periods.sort((a, b) => new Date(a.startDate).getTime() - new Date(b.startDate).getTime());
    }
  }
}

