@Service()
export class PriceSettingService {
  constructor(
    private readonly repo: PriceSettingRepository,
    private readonly roomRepo: RoomRepository,
    private readonly seasonRepo: SeasonRepository,
    private readonly hotelRepo: HotelRepository,
    private readonly countryRepo: GeoCountryRepository,
    private readonly rateCalendarRepo: RateCalendarRepository,
    private readonly surchargeFeeSettingRepo: SurchargeFeeSettingRepository,
  ) {}

  /**
   * Validate format của periods
   */
  private validatePeriodsFormat(periods: RangeDate[]) {
    if (!periods || !Array.isArray(periods) || periods.length === 0) {
      throw new BusinessLogicError(ErrorCode.PERIODS_REQUIRED);
    }

    for (const dateRange of periods) {
      if (!dateRange.startDate || !dateRange.endDate) {
        throw new BusinessLogicError(ErrorCode.PERIODS_INVALID);
      }

      const startDate = dayjs(dateRange.startDate);
      const endDate = dayjs(dateRange.endDate);

      if (!startDate.isValid() || !endDate.isValid()) {
        throw new BusinessLogicError(ErrorCode.PERIODS_INVALID);
      }

      if (startDate.isAfter(endDate)) {
        throw new BusinessLogicError(ErrorCode.PERIODS_INVALID);
      }
    }
  }

  /**
   * Check trùng lặp dựa trên:
   * - Loại phòng (room)
   * - Meal plan (mealPlan)
   * - Thị trường khách (countries)
   * - Loại ngày áp dụng (dayType)
   * - Điều kiện hoàn hủy (condition)
   *
   * Nếu các điều kiện trên trùng hoàn toàn thì check:
   * - Mùa trùng mùa (cùng seasonId)
   * - Mùa trùng thời gian tùy chỉnh (periods overlap)
   * - Sự kiện trùng sự kiện (cùng eventId trong season)
   */
  private async checkDuplicate(
    hotelId: number,
    roomId: number,
    mealPlan: MealPlan,
    countryIds: number[],
    dayType: DayType | null,
    condition: CancellationType,
    seasonId: number | null,
    periods: RangeDate[],
    excludeId?: number,
  ) {
    const duplicate = await this.repo.findDuplicateStrict(
      hotelId,
      roomId,
      mealPlan,
      countryIds,
      dayType,
      condition,
      seasonId,
      periods,
      excludeId,
    );

    if (duplicate) {
      throw new BusinessLogicError(ErrorCode.PRICE_SETTING_DUPLICATE);
    }
  }

  private getNameRatePlan(
    condition: CancellationType,
    mealPlan: string,
    roomName: string,
    amount?: number,
    unitType?: UnitType,
  ) {
    const nameConditionMap = {
      [CancellationType.NO_CANCELLATION]: 'NR',
      [CancellationType.FREE_CANCELLATION]: 'Free Cancel',
      [CancellationType.CANCELLATION_CHARGE]: `${amount}${unitType === UnitType.PERCENTAGE ? '%' : 'VND'} Refund`,
    };
    return [roomName, mealPlan, nameConditionMap[condition]].filter(Boolean).join(' - ');
  }

  private clonePeriods(periods?: RangeDate[] | null) {
    if (!periods || !Array.isArray(periods)) return [];
    return periods.map(period => ({ ...period }));
  }

  private buildStayDates(periods?: RangeDate[] | null) {
    if (!periods || !Array.isArray(periods) || periods.length === 0) return [];
    const stayDates = new Set<string>();
    for (const period of periods) {
      const start = dayjs(period.startDate).startOf('day');
      const end = dayjs(period.endDate).startOf('day');
      if (!start.isValid() || !end.isValid() || start.isAfter(end)) {
        continue;
      }
      for (let cursor = start; !cursor.isAfter(end); cursor = cursor.add(1, 'day')) {
        stayDates.add(cursor.format('YYYY-MM-DD'));
      }
    }
    return Array.from(stayDates.values());
  }

  private async syncRateCalendar(priceSetting: PriceSetting, previousPeriods: RangeDate[] = []) {
    const hotelId = priceSetting.hotel?.id;
    const roomId = priceSetting.room?.id;
    if (!hotelId || !roomId) return;

    const previousStayDates = this.buildStayDates(previousPeriods);
    if (previousStayDates.length > 0) {
      await this.rateCalendarRepo.deleteByHotelRoomAndDates(hotelId, roomId, previousStayDates);
    }

    if (!priceSetting.isActive) {
      return;
    }

    const nextStayDates = this.buildStayDates(priceSetting.periods);
    if (!nextStayDates.length) {
      return;
    }
    // Defensive clean-up in case stale rows exist for the same dates
    await this.rateCalendarRepo.deleteByHotelRoomAndDates(hotelId, roomId, nextStayDates);

    const auditUser = priceSetting.updatedBy || priceSetting.createdBy;
    const rateCalendars = nextStayDates.map(dateStr => {
      const rateCalendar = new RateCalendar();
      rateCalendar.hotel = priceSetting.hotel;
      rateCalendar.hotelId = hotelId;
      rateCalendar.room = priceSetting.room;
      rateCalendar.roomId = roomId;
      rateCalendar.stayDate = dayjs(dateStr).toDate();
      rateCalendar.baseRate = priceSetting.price;
      rateCalendar.ownerId = priceSetting.ownerId;
      const createdBy = priceSetting.createdBy || auditUser;
      const updatedBy = priceSetting.updatedBy || createdBy;
      rateCalendar.createdBy = createdBy;
      rateCalendar.updatedBy = updatedBy;
      return rateCalendar;
    });

    await this.rateCalendarRepo.saveMany(rateCalendars);
  }

