import { MigrationInterface, QueryRunner } from 'typeorm';
import dayjs from 'dayjs';

import { PriceSetting } from '@Entities/PriceSetting';
import { RateCalendar } from '@Entities/RateCalendar';

export class MigrateRateCalendar1765264860765 implements MigrationInterface {
  public async up(queryRunner: QueryRunner): Promise<void> {
    // query priceSetting
    const priceSettings = await queryRunner.connection
      .getRepository(PriceSetting)
      .find({ where: { isActive: true }, relations: ['hotel', 'room'] });
    console.log(`Found ${priceSettings.length} active price settings.`);
    // generate rateCalendar based on priceSetting
    for (const priceSetting of priceSettings) {
      const stayDates: Date[] = [];
      const rateCalendars: RateCalendar[] = [];
      const periods = priceSetting.periods || [];

      for (const period of periods) {
        const start = dayjs(period.startDate).startOf('day');
        const end = dayjs(period.endDate).startOf('day');

        const days = end.diff(start, 'day') + 1;

        for (let i = 0; i < days; i++) {
          stayDates.push(start.add(i, 'day').toDate());
        }
      }

      if (!stayDates.length) {
        continue;
      }

      for (const stayDate of stayDates) {
        const existed = await queryRunner.manager.findOne(RateCalendar, {
          where: {
            hotelId: priceSetting.hotel.id,
            roomId: priceSetting.room.id,
            stayDate,
          },
        });

        if (existed) {
          continue;
        }

        const rateCalendar = new RateCalendar();
        rateCalendar.hotel = priceSetting.hotel;
        rateCalendar.hotelId = priceSetting.hotel.id;
        rateCalendar.room = priceSetting.room;
        rateCalendar.roomId = priceSetting.room.id;
        rateCalendar.stayDate = stayDate;
        rateCalendar.baseRate = priceSetting.price;
        rateCalendar.ownerId = priceSetting.ownerId;
        rateCalendar.createdBy = priceSetting.createdBy;
        rateCalendars.push(rateCalendar);
      }

      if (!rateCalendars.length) {
        console.log(`Không có rate calendar mới cho price setting: ${priceSetting.name}.`);
        continue;
      }

      await queryRunner.manager.save(rateCalendars);
      console.log(
        `Migrate rate calendar cho price setting: ${priceSetting.name} hoàn tất.
         Đã tạo ${rateCalendars.length} bản ghi.`,
      );
    }
  }

  public async down(queryRunner: QueryRunner): Promise<void> {}
}

