import { HotelStatus } from '@Enums/Hotel';
import { FeeRuleMethod, FeeRuleScope, FeeRuleType } from '@Enums/FeeRule';
import { RatePromotionType } from '@Enums/RatePromotion';

import { ConflictError } from '@Errors/ConflictError';
import { ErrorCode } from '@Errors/ErrorCode';

import { Hotel } from '@Entities/Hotel';
import { FeeRule } from '@Entities/FeeRule';
import { RatePromotion } from '@Entities/RatePromotion';

import { DestinationRepository } from '@Repositories/DestinationRepository';
import { FeeRuleRepository } from '@Repositories/FeeRuleRepository';
import { HotelRepository } from '@Repositories/HotelRepository';
import { RateCalendarRepository, AggregatedRateRow } from '@Repositories/RateCalendarRepository';
import { RatePromotionRepository } from '@Repositories/RatePromotionRepository';
import { RoomRepository } from '@Repositories/RoomRepository';

import {
  HotelPriceRoomSelection,
  HotelPriceSearchItem,
  HotelPriceSearchParams,
  HotelPriceSearchResponse,
  HotelSearchSuggestionQuery,
  HotelSearchSuggestionResponse,
  HotelSearchRoomDto,
  HotelPriceOption,
  HotelSearchSuggestItem,
  HotelSearchRoomInfo,
} from '@Rests/types/HotelSearchDto';

@Service()
export class HotelSearchService {
  constructor(
    private readonly destinationRepo: DestinationRepository,
    private readonly hotelRepo: HotelRepository,
    private readonly rateCalendarRepo: RateCalendarRepository,
    private readonly ratePromotionRepo: RatePromotionRepository,
    private readonly feeRuleRepo: FeeRuleRepository,
    private readonly roomRepo: RoomRepository,
    @Inject('cache') private readonly cache: Redis.Redis,
  ) {}

  async completions(params: HotelSearchSuggestionQuery): Promise<HotelSearchSuggestionResponse> {
    const { q, limit = 10 } = params;
    const maxDestinations = Math.min(3, limit);
    const minScore = 0.001;
    const hotelWeight = 1.0;
    const destinationWeight = 0.9; // prefer hotels slightly

    const destinations = await this.destinationRepo.fullTextSearch(q, maxDestinations);
    const hotels = await this.hotelRepo.fullTextSearch(q, limit);

    const items: HotelSearchSuggestItem[] = [];

    destinations.forEach(d => {
      const score = (d as any).score ?? 0;
      if (score >= minScore) {
        items.push({
          type: 'DESTINATION',
          id: d.id,
          name: d.name,
          score: score * destinationWeight,
          destination: d,
        });
      }
    });

    hotels.forEach(h => {
      const score = (h as any).score ?? 0;
      if (score >= minScore) {
        items.push({
          type: 'HOTEL',
          id: h.id,
          name: h.localName || h.globalName || h.code,
          score: score * hotelWeight,
          hotel: h,
        });
      }
    });

    items.sort((a, b) => b.score - a.score);

    const limited: HotelSearchSuggestItem[] = [];
    let destinationCount = 0;
    for (const item of items) {
      if (limited.length >= limit) break;
      if (item.type === 'DESTINATION') {
        if (destinationCount >= maxDestinations) continue;
        destinationCount += 1;
      }
      limited.push(item);
    }

    const response = new HotelSearchSuggestionResponse();
    response.suggestions = limited;
    response.destinations = limited.filter(i => i.type === 'DESTINATION').map(i => i.destination!) as any;
    response.hotels = limited.filter(i => i.type === 'HOTEL').map(i => i.hotel!) as any;
    return response;
  }

  async searchPrices(params: HotelPriceSearchParams): Promise<HotelPriceSearchResponse> {
    const {
      destinationId,
      hotelId,
      checkInDate,
      checkOutDate,
      rooms = [{ adults: 1 }],
      page = 1,
      size = 10,
      searchId,
    } = params;

    if (!checkInDate || !checkOutDate) {
      throw new ConflictError(ErrorCode.INVALID_DATE_RANGE);
    }
    if (destinationId && hotelId) {
      throw new ConflictError(ErrorCode.SEARCH_INPUT_CONFLICT);
    }
    if (!destinationId && !hotelId) {
      throw new ConflictError(ErrorCode.SEARCH_TARGET_REQUIRED);
    }
    const checkIn = dayjs(checkInDate);
    const checkOut = dayjs(checkOutDate);
    if (!checkOut.isAfter(checkIn)) {
      throw new ConflictError(ErrorCode.CHECK_IN_DATE_MUST_BE_BEFORE_CHECK_OUT_DATE);
    }
    const stayNights = checkOut.diff(checkIn, 'day');
    if (stayNights <= 0) {
      throw new ConflictError(ErrorCode.INVALID_DATE_RANGE);
    }

    const normalizedRooms = this.normalizeRooms(rooms);
    const computedSearchId = this.buildSearchId(destinationId, hotelId, checkIn, checkOut, normalizedRooms);
    const derivedSearchId = searchId && searchId === computedSearchId ? searchId : computedSearchId;

    // try cache first
    const cached = await this.readCache(derivedSearchId);
    if (cached) {
      const paged = this.sliceResults(cached.items, page, size);
      return this.buildResponse(paged.items, cached.total, page, size, derivedSearchId, paged.nextCursor);
    }

    const destinationHotelIds = await this.resolveHotelIds(destinationId, hotelId);
    if (!destinationHotelIds.length) {
      return new HotelPriceSearchResponse()
        .withItems([])
        .withTotal(0)
        .withPage(page)
        .withSize(size)
        .withSortBy('netTotal')
        .withSortDirection(undefined as any) as any;
    }

    // limit candidate hotels to the cheapest 100 (by lowest room base total) to avoid loading all rates
    const candidateLimit = 100;
    const aggregatedRates = await this.rateCalendarRepo.aggregateByStayDates(
      destinationHotelIds,
      checkIn.format('YYYY-MM-DD'),
      checkOut.format('YYYY-MM-DD'),
      candidateLimit,
    );
    if (!aggregatedRates.length) {
      return new HotelPriceSearchResponse().withItems([]).withTotal(0).withPage(page).withSize(size);
    }
    const roomMap = await this.buildRoomMap(aggregatedRates);

    const promotions = await this.ratePromotionRepo.findApplicable(
      destinationHotelIds,
      checkIn.format('YYYY-MM-DD'),
      checkOut.format('YYYY-MM-DD'),
    );
    const feeRules = await this.feeRuleRepo.findActiveByHotels(destinationHotelIds);

    const groupedByHotel = this.groupRatesByHotel(aggregatedRates);
    const hotelIds = Array.from(groupedByHotel.keys());
    const hotels = await this.hotelRepo.find({ where: { id: In(hotelIds) } });
    const hotelMap = new Map<number, Hotel>();
    hotels.forEach(h => {
      if (h.status === HotelStatus.ACTIVE) hotelMap.set(h.id, h);
    });

    const results: HotelPriceSearchItem[] = [];
    for (const [hotelId, rateRows] of groupedByHotel) {
      const assignment = this.assignRooms(rateRows, rooms, roomMap);
      if (!assignment) continue;

      const baseTotal = assignment.reduce((acc, item) => acc + item.baseTotal, 0);
      const hotelPromos = promotions.filter(p => Number(p.hotelId) === hotelId);
      const promoResult = this.applyPromotions(baseTotal, stayNights, hotelPromos, assignment);
      const hotelFeeRules = feeRules.filter(rule => Number(rule.hotelId) === hotelId);
      const feeTotal = this.applyFees(promoResult.totalAfterPromo, hotelFeeRules, stayNights, rooms);
      const options = this.buildRoomOptions(rateRows, rooms, roomMap);

      const item = new HotelPriceSearchItem();
      const hotel = hotelMap.get(hotelId);
      if (!hotel) continue;
      item.hotel = hotel;
      item.baseTotal = baseTotal;
      item.discountTotal = promoResult.discountTotal;
      item.feeTotal = feeTotal;
      item.netTotal = promoResult.totalAfterPromo + feeTotal;
      item.nights = stayNights;
      item.rooms = assignment;
      item.options = options;
      results.push(item);
    }

    results.sort((a, b) => a.netTotal - b.netTotal);
    const total = results.length;
    await this.writeCache(derivedSearchId, { items: results, total });

    const paged = this.sliceResults(results, page, size);
    return this.buildResponse(paged.items, total, page, size, derivedSearchId, paged.nextCursor);
  }

  private async resolveHotelIds(destinationId?: number, hotelId?: number): Promise<number[]> {
    if (hotelId) {
      const hotel = await this.hotelRepo.findOne({ where: { id: hotelId, status: HotelStatus.ACTIVE } });
      return hotel ? [hotel.id] : [];
    }

    if (!destinationId) return [];
    const destination = await this.destinationRepo.findOne({ where: { id: destinationId } });
    if (!destination) return [];

    const mapped = await this.destinationRepo.findHotelIds(destination.id);
    if (mapped.length) return mapped;

    const qb = this.hotelRepo
      .createQueryBuilder('hotel')
      .select('hotel.id', 'id')
      .leftJoin('hotel.ward', 'ward')
      .leftJoin('ward.district', 'district')
      .leftJoin('district.city', 'city')
      .where('hotel.status = :status', { status: HotelStatus.ACTIVE });

    if (destination.cityId) qb.andWhere('city.id = :cityId', { cityId: destination.cityId });
    if (destination.districtId) qb.andWhere('district.id = :districtId', { districtId: destination.districtId });
    if (destination.wardId) qb.andWhere('ward.id = :wardId', { wardId: destination.wardId });

    const rows = await qb.getRawMany();
    return rows.map(row => Number(row.id));
  }

  private groupRatesByHotel(rows: AggregatedRateRow[]): Map<number, AggregatedRateRow[]> {
    const grouped = new Map<number, AggregatedRateRow[]>();
    rows.forEach(row => {
      const list = grouped.get(row.hotelId) || [];
      list.push(row);
      grouped.set(row.hotelId, list);
    });
