  private applyPromotions(
    baseTotal: number,
    stayNights: number,
    promotions: RatePromotion[],
    selection: HotelPriceRoomSelection[],
  ) {
    if (!promotions.length) {
      return { discountTotal: 0, totalAfterPromo: baseTotal };
    }
    // take highest priority then highest discount
    const sorted = promotions.sort((a, b) => b.priority - a.priority);
    let bestDiscount = 0;
    sorted.forEach(promo => {
      const discount = this.calculateDiscount(baseTotal, stayNights, promo);
      if (discount > bestDiscount) bestDiscount = discount;
    });
    const totalAfterPromo = Math.max(0, baseTotal - bestDiscount);
    return { discountTotal: bestDiscount, totalAfterPromo };
  }

  private calculateDiscount(baseTotal: number, stayNights: number, promo: RatePromotion): number {
    switch (promo.promoType) {
      case RatePromotionType.PERCENT:
        return (baseTotal * Number(promo.value)) / 100;
      case RatePromotionType.FIXED:
        return Number(promo.value);
      case RatePromotionType.STAY_PAY: {
        const payNights = Math.max(1, Number(promo.value));
        const freeNights = Math.floor(stayNights / (payNights + 1));
        const avgNight = baseTotal / stayNights;
        return freeNights * avgNight;
      }
      default:
        return 0;
    }
  }

  private applyFees(
    amountAfterPromo: number,
    feeRules: FeeRule[],
    stayNights: number,
    roomRequests: HotelSearchRoomDto[],
  ): number {
    if (!feeRules.length) return 0;
    const totalGuests = roomRequests.reduce((acc, r) => acc + this.getGuestCount(r), 0);
    let totalFee = 0;

    feeRules.forEach(rule => {
      const value = Number(rule.value);
      const scopeMultiplier =
        rule.scope === FeeRuleScope.PER_NIGHT ? stayNights : rule.scope === FeeRuleScope.PER_GUEST ? totalGuests : 1;

      switch (rule.feeType) {
        case FeeRuleType.SERVICE_CHARGE:
        case FeeRuleType.TAX:
        case FeeRuleType.FIXED_FEE: {
          const fee = rule.method === FeeRuleMethod.PERCENT ? (amountAfterPromo * value) / 100 : value;
          totalFee += fee * scopeMultiplier;
          break;
        }
        case FeeRuleType.EXTRA_ADULT:
        case FeeRuleType.EXTRA_CHILD: {
          const count =
            rule.feeType === FeeRuleType.EXTRA_ADULT
              ? roomRequests.reduce((acc, r) => acc + r.adults, 0)
              : roomRequests.reduce((acc, r) => acc + (r.children?.length || 0), 0);
          const fee = rule.method === FeeRuleMethod.PERCENT ? (amountAfterPromo * value) / 100 : value;
          const extraMultiplier =
            rule.scope === FeeRuleScope.PER_NIGHT
              ? stayNights * count
              : rule.scope === FeeRuleScope.PER_GUEST
              ? count
              : count;
          totalFee += fee * extraMultiplier;
          break;
        }
        default:
          break;
      }
    });

    return totalFee;
  }

  private getGuestCount(room: HotelSearchRoomDto) {
    return (room.adults || 0) + (room.children?.length || 0);
  }
