    const destination = await this.destinationRepo.findOne({ where: { id: destinationId } });
    if (!destination) return [];

    const mapped = await this.destinationRepo.findHotelIds(destination.id);
    if (mapped.length) return mapped;

    const qb = this.hotelRepo
      .createQueryBuilder('hotel')
      .select('hotel.id', 'id')
      .leftJoin('hotel.ward', 'ward')
      .leftJoin('ward.district', 'district')
      .leftJoin('district.city', 'city')
      .where('hotel.status = :status', { status: HotelStatus.ACTIVE });

    if (destination.cityId) qb.andWhere('city.id = :cityId', { cityId: destination.cityId });
