    });
  }

  async suggestHotels(
    q: string,
    cityId?: number,
    lat?: number,
    lng?: number,
    limitCount: number = 10,
    cursorScore?: number,
    cursorId?: number,
  ) {
    const query = `
      SELECT * FROM suggest_hotels(
        $1::text,
        $2::int,
        $3::double precision,
        $4::double precision,
        $5::int,
        $6::double precision,
        $7::int
      )
    `;

